// ── SISTEMA DE RATING — TABELA OFICIAL CBTM (Regulamento v03-8, Cap. 05) ──────
// Tabela Básica de Cálculo do Rating do Manual Tênis de Mesa Brasil (item 1.7.2.4.5)
// Valores por faixa de diferença de rating. Usados sempre com peso 1 (rodada
// regular). O torneio presencial é só pódio/prêmios — NÃO afeta o rating.

// Favorito vence (quem tem rating MAIOR ou igual ganha): ganha pouco
const CBTM_FAVORITO = [
  { max: 24,   v: 10, p: -8 },
  { max: 49,   v: 9,  p: -7 },
  { max: 99,   v: 8,  p: -6 },
  { max: 149,  v: 7,  p: -5 },
  { max: 199,  v: 6,  p: -4 },
  { max: 299,  v: 5,  p: -3 },
  { max: 399,  v: 4,  p: -2 },
  { max: 499,  v: 3,  p: -1 },
  { max: 749,  v: 2,  p: 0  },
  { max: Infinity, v: 1, p: 0 },
];

// Azarão vence (quem tem rating MENOR ganha): ganha muito
const CBTM_AZARAO = [
  { max: 24,   v: 11, p: -9  },
  { max: 49,   v: 12, p: -10 },
  { max: 99,   v: 14, p: -11 },
  { max: 149,  v: 16, p: -12 },
  { max: 199,  v: 18, p: -14 },
  { max: 299,  v: 20, p: -16 },
  { max: 399,  v: 23, p: -18 },
  { max: 499,  v: 26, p: -20 },
  { max: Infinity, v: 30, p: -22 },
];

// Retorna { vencedor, perdedor } — variação de pontos de cada um
function calcRatingCBTM(ratingVencedor, ratingPerdedor, peso = 1) {
  const diff = Math.abs(ratingVencedor - ratingPerdedor);
  // Azarão = quem venceu tinha rating MENOR que o adversário
  const azaraoVenceu = ratingVencedor < ratingPerdedor;
  const tabela = azaraoVenceu ? CBTM_AZARAO : CBTM_FAVORITO;
  const faixa = tabela.find(f => diff <= f.max);
  return {
    vencedor: faixa.v * peso,
    perdedor: faixa.p * peso,
  };
}

// Wrapper de compatibilidade: recebe ratings e quem ganhou (1 = ra venceu, 0 = rb venceu)
// Retorna o NOVO rating de "ra". Usa peso 1 (rodada regular) por padrão.
function calcElo(ra, rb, result, peso = 1) {
  if (result === 1) {
    // ra venceu
    const d = calcRatingCBTM(ra, rb, peso);
    return ra + d.vencedor;
  } else {
    // ra perdeu (rb venceu)
    const d = calcRatingCBTM(rb, ra, peso);
    return ra + d.perdedor;
  }
}

// ── ROUND ROBIN ──────────────────────────────────────────────────────────────
// ── PAREAMENTO POR RATING (Regulamento Cap. 03) ──────────────────────────────
// Retorna a lista de confrontos já ocorridos na temporada, como set de chaves "idA|idB"
function confrontosDaTemporada(matches) {
  const set = new Set();
  matches.forEach(m => {
    if (m.p1Id && m.p2Id) {
      const [a, b] = [m.p1Id, m.p2Id].sort();
      set.add(`${a}|${b}`);
    }
  });
  return set;
}

function jaSeEnfrentaram(idA, idB, historico) {
  const [a, b] = [idA, idB].sort();
  return historico.has(`${a}|${b}`);
}

// Pareia uma rodada única (Regulamento Cap. 03). Regra:
//   1) EVITAR AO MÁXIMO a repetição de confrontos na temporada — prioridade
//      absoluta, independentemente do rating.
//   2) Quando a repetição for inevitável, escolher os reencontros de rating
//      mais próximo.
// Implementação: emparelhamento de custo mínimo, onde um reencontro custa muito
// mais que qualquer diferença de rating. Assim minimiza-se PRIMEIRO o número de
// repetições e, só como desempate, a diferença de rating.
// Retorna { pares: [{p1,p2}], bye: idOuNull }
function parearRodada(athletes, historico) {
  const sorted = [...athletes].sort((a, b) => (b.rating || 250) - (a.rating || 250));

  // Ímpar: o atleta de menor rating folga (bye), sem pontos.
  let byeId = null;
  let jogadores = sorted;
  if (sorted.length % 2 !== 0) {
    byeId = sorted[sorted.length - 1].id;
    jogadores = sorted.slice(0, -1);
  }

  const n = jogadores.length;
  const PENAL_REPETICAO = 1e7; // reencontro domina qualquer diferença de rating

  function custo(i, j) {
    const repetido = jaSeEnfrentaram(jogadores[i].id, jogadores[j].id, historico) ? PENAL_REPETICAO : 0;
    return repetido + Math.abs((jogadores[i].rating || 250) - (jogadores[j].rating || 250));
  }

  const usados = new Array(n).fill(false);
  let melhorPares = null, melhorCusto = Infinity;

  function resolver(pares, custoAcc) {
    if (custoAcc >= melhorCusto) return; // poda: este caminho já não melhora
    const i = usados.findIndex(u => !u);
    if (i === -1) { melhorCusto = custoAcc; melhorPares = pares; return; }
    usados[i] = true;
    const candidatos = [];
    for (let j = 0; j < n; j++) {
      if (j === i || usados[j]) continue;
      candidatos.push({ j, c: custo(i, j) });
    }
    candidatos.sort((a, b) => a.c - b.c); // tenta os melhores primeiro (poda mais cedo)
    for (const { j, c } of candidatos) {
      usados[j] = true;
      resolver([...pares, { p1: jogadores[i].id, p2: jogadores[j].id }], custoAcc + c);
      usados[j] = false;
    }
    usados[i] = false;
  }
  resolver([], 0);

  return { pares: melhorPares || [], bye: byeId };
}

// Gera o PAR MENSAL (2 rodadas) por rating, com anti-repetição na temporada.
// A 2ª rodada é pareada com o mesmo rating vigente do início do mês (Cap. 03),
// considerando os confrontos da rodada 1 recém-gerada como já ocorridos.
function gerarPareamentoPorRating(athletes, matchesTemporada = []) {
  const historico = confrontosDaTemporada(matchesTemporada);

  // Rodada 1
  const r1 = parearRodada(athletes, historico);

  // Para a rodada 2, os confrontos da rodada 1 também contam como "já ocorridos"
  const historico2 = new Set(historico);
  r1.pares.forEach(par => {
    const [a, b] = [par.p1, par.p2].sort();
    historico2.add(`${a}|${b}`);
  });

  const r2 = parearRodada(athletes, historico2);

  return {
    rodada1: r1.pares, bye1: r1.bye,
    rodada2: r2.pares, bye2: r2.bye,
  };
}

