function reducer(state, action) {
  switch (action.type) {

    case "INSCRICAO_ADD": {
      const { name, phone, apelido, federated, rating, aceiteRegulamento, aceiteLGPD, dataAceite, ipAceite } = action.payload;
      // A checagem de telefone duplicado agora acontece ANTES do dispatch
      // (busca assíncrona estreita, sem precisar da lista inteira de
      // atletas no cliente) — e o banco tem uma trava de unicidade real
      // como rede de segurança. Esse case só cria o registro otimista local.
      const telFormatado = phone.replace(/\D/g, "");
      const id = Date.now();
      const ath = {
        id, name, phone: telFormatado, apelido: apelido || null, federated,
        rating: federated ? (rating || null) : 250,
        status: "pendente", key: null,
        aceiteRegulamento: aceiteRegulamento || false,
        dataAceiteRegulamento: dataAceite || null,
        versaoRegulamento: "v03-8",
        aceiteLGPD: aceiteLGPD || false,
        dataAceiteLGPD: dataAceite || null,
        inscritoEm: dataAceite || new Date().toISOString(),
      };
      return { ...state, athletes: [...state.athletes, ath] };
    }

    case "INSCRICAO_VALIDAR": {
      const { id, rating, approved, motivo } = action.payload;
      if (approved) {
        const updated = state.athletes.map(a =>
          a.id === id ? { ...a, status: "ativo", rating: rating || a.rating, ratingInicial: rating || a.rating, saldoTemp: 0, pendenteCircuito: true } : a
        );
        return { ...state, athletes: updated };
      } else {
        const updated = state.athletes.map(a =>
          a.id === id ? { ...a, status: "reprovado", motivo } : a
        );
        return { ...state, athletes: updated };
      }
    }

    case "INCLUIR_NO_CIRCUITO": {
      const { id } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === id ? { ...a, pendenteCircuito: false } : a
      );
      return { ...state, athletes };
    }

    case "RECUSAR_CIRCUITO": {
      const { id } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === id ? { ...a, ultimaRecusaCircuitoEm: new Date().toISOString() } : a
      );
      return { ...state, athletes };
    }

    case "ARQUIVAR_ATLETA": {
      const { id } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === id ? { ...a, status: "arquivado", pendenteCircuito: false } : a
      );
      return { ...state, athletes };
    }

    case "INICIAR_ETAPA": {
      const ativos = state.athletes.filter(a => a.status === "ativo" && !a.pendenteCircuito);
      const athletesUpdated = state.athletes.map(a =>
        (a.status === "ativo" && !a.pendenteCircuito) ? { ...a, key: "key_1" } : a
      );

      // Pareamento por rating (Cap. 03) — gera o par mensal (2 rodadas) sem repetição
      const { rodada1, rodada2, bye1, bye2 } = gerarPareamentoPorRating(ativos, []);

      // Prazos por calendário fixo mensal (Cap. 01/13): R1 até dia 15, R2 até dia 25
      const hoje = new Date();
      const ano = hoje.getFullYear(), mes = hoje.getMonth();
      const prazoR1 = new Date(ano, mes, 15).toISOString().split("T")[0];
      const prazoR2 = new Date(ano, mes, 25).toISOString().split("T")[0];

      const key = {
        id: "key_1", name: "Chave Única",
        athleteIds: ativos.map(a => a.id),
        currentRound: 1,
        byes: { 1: bye1, 2: bye2 },
      };

      const mkMatch = (pair, round, prazo) => ({
        id: `m_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
        keyId: "key_1", round,
        p1Id: pair.p1, p2Id: pair.p2,
        score1: null, score2: null,
        p1Submitted: null, p2Submitted: null,
        validated: false,
        deadline: prazo, scoreDeadline: prazo,
      });

      // Publica as DUAS rodadas do mês de uma vez (Cap. 01)
      const matches = [
        ...rodada1.map(p => mkMatch(p, 1, prazoR1)),
        ...rodada2.map(p => mkMatch(p, 2, prazoR2)),
      ];

      return { ...state, athletes: athletesUpdated, keys: [key], matches, phase: "etapa" };
    }

    case "NOVA_TEMPORADA": {
      // Antes de zerar, tira uma "foto" da posição final de cada atleta ativo
      // (mesmo critério do RankingView: ativo, fora do backlog, ordenado por saldo)
      // e guarda no histórico — é o que alimenta a carta colecionável.
      const rankingFinal = [...state.athletes]
        .filter(a => estaNoRanking(a, state.matches))
        .sort(cmpRanking(state.matches));
      const rotuloTemporada = `${state.temporadaNumero}/${state.temporadaAno}`;
      const posicaoFinal = {};
      rankingFinal.forEach((a, i) => { posicaoFinal[a.id] = i + 1; });

      // Zera saldo de pontos, vitórias e derrotas da temporada.
      // Preserva o rating (nunca zera) e acumula o histórico de vitórias/derrotas.
      const athletes = state.athletes.map(a => {
        if (a.status !== "ativo") return a;
        const historicoAtualizado = posicaoFinal[a.id]
          ? [{ temporada: rotuloTemporada, pos: posicaoFinal[a.id] }, ...(a.historico || [])]
          : (a.historico || []);
        return {
          ...a,
          winsTotal: (a.winsTotal || 0) + (a.wins || 0),
          lossesTotal: (a.lossesTotal || 0) + (a.losses || 0),
          saldoTemp: 0,
          wins: 0,
          losses: 0,
          historico: historicoAtualizado,
        };
      });

      // Avança o contador: 3 temporadas por ano (Cap. 13), depois vira o ano
      const proximoNumero = state.temporadaNumero >= 3 ? 1 : state.temporadaNumero + 1;
      const proximoAno = state.temporadaNumero >= 3 ? state.temporadaAno + 1 : state.temporadaAno;

      // Limpa partidas e chaves da temporada anterior, volta para fase de inscrições
      return {
        ...state, athletes, matches: [], keys: [], phase: "inscricoes",
        temporadaNumero: proximoNumero, temporadaAno: proximoAno,
      };
    }

    case "MARCAR_RESULTADO_COMUNICADO": {
      const { matchId, comunicado } = action.payload;
      const matches = state.matches.map(m =>
        m.id === matchId ? { ...m, resultadoComunicado: comunicado } : m
      );
      return { ...state, matches };
    }

    case "SUBMIT_RESULT": {
      const { matchId, athleteId, score1, score2 } = action.payload;
      const updated = state.matches.map(m => {
        if (m.id !== matchId) return m;
        if (m.p1Id === athleteId) return { ...m, p1Submitted: { score1, score2 }, p1SubAt: new Date().toISOString() };
        if (m.p2Id === athleteId) return { ...m, p2Submitted: { score1, score2 }, p2SubAt: new Date().toISOString() };
        return m;
      });
      return { ...state, matches: updated };
    }

    case "VALIDATE_RESULT": {
      const { matchId, approved, motivo } = action.payload;
      if (!approved) {
        const updated = state.matches.map(m =>
          m.id === matchId ? { ...m, rejeitado: true, motivoRejeicao: motivo } : m
        );
        return { ...state, matches: updated };
      }
      // Aqui só confirmamos o placar — o rating/saldo NÃO é aplicado ainda.
      // Isso evita que um jogo da Rodada 2 realizado cedo (dentro da janela da
      // Rodada 1) altere o rating antes do prazo da Rodada 1 fechar (Cap. 08).
      // O cálculo em si acontece depois, via PROCESSAR_RODADA.
      const now = new Date().toISOString();
      const matches = state.matches.map(m =>
        m.id === matchId
          ? { ...m, validated: true, validadoPorAdmin: true, adminAprovadoEm: now, score1: m.p1Submitted.score1, score2: m.p1Submitted.score2, calculado: false }
          : m
      );
      return { ...state, matches };
    }

    case "DESFAZER_VALIDACAO": {
      // Desfaz uma validação feita por engano. Só é permitido enquanto o
      // rating ainda não foi calculado (m.calculado === false) — depois
      // disso, desfazer exigiria reverter o rating também, o que é bem
      // mais arriscado (pode cascatear em outras partidas já calculadas
      // em cima desse rating). O placar volta a ficar "aguardando validação",
      // mantendo o que os dois atletas enviaram.
      const { matchId } = action.payload;
      const alvo = state.matches.find(m => m.id === matchId);
      if (!alvo || alvo.calculado) return state;
      const matches = state.matches.map(m =>
        m.id === matchId
          ? { ...m, validated: false, validadoPorAdmin: false, adminAprovadoEm: null, score1: null, score2: null, imputadoPeloAdmin: false }
          : m
      );
      return { ...state, matches };
    }

    case "ADMIN_IMPUTAR_RESULTADO": {
      // Casos extremos: atleta sumiu, disputa sem acordo, W.O. que precisa
      // virar resultado oficial. O admin registra o placar diretamente,
      // ignorando o que os atletas enviaram (se enviaram algo). Fica
      // marcado como "imputadoPeloAdmin" pra transparência — o atleta e
      // o histórico sempre mostram que essa não foi uma confirmação mútua.
      const { matchId, score1, score2 } = action.payload;
      const now = new Date().toISOString();
      const matches = state.matches.map(m =>
        m.id === matchId
          ? { ...m, validated: true, validadoPorAdmin: true, adminAprovadoEm: now, score1, score2, calculado: false, imputadoPeloAdmin: true }
          : m
      );
      return { ...state, matches };
    }

    case "ATUALIZAR_FOTO_ATLETA": {
      // Atleta subiu (ou removeu) sua própria foto de perfil. A imagem em si
      // já foi enviada pro Supabase Storage antes desse dispatch — aqui só
      // guardamos a URL pública resultante.
      const { athleteId, url } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === athleteId ? { ...a, foto: url } : a
      );
      return { ...state, athletes };
    }

    case "ATUALIZAR_ESTILO_ATLETA": {
      // Estilo de jogo do atleta (Clássico / Caneta Chinesa / Caneta Japonesa) —
      // usado na carta colecionável full-art como o "tipo".
      const { athleteId, estilo } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === athleteId ? { ...a, estilo } : a
      );
      return { ...state, athletes };
    }

    case "REGISTRAR_MENSAGEM_ENVIADA": {
      // Log de disparo de WhatsApp — guarda o texto exatamente como foi
      // enviado, pra "Reenviar" funcionar igual mesmo se o dado de origem
      // (rating, ranking etc.) já tiver mudado depois. matchId (quando a
      // categoria é por-partida, como "resultados"/"lembretes") permite
      // diferenciar "já mandei o resultado DESSA partida" de "já mandei
      // ALGUM resultado esse mês" — sem isso, a 2ª partida do mês de um
      // atleta ficava presa depois que a 1ª já tinha sido comunicada.
      const { id, athleteId, athleteName, categoria, categoriaLabel, texto, enviadoEm, matchId } = action.payload;
      return {
        ...state,
        mensagensEnviadas: [
          { id, athleteId, athleteName, categoria, categoriaLabel, texto, enviadoEm, matchId: matchId || null },
          ...state.mensagensEnviadas,
        ].slice(0, 200),
      };
    }

    case "SOLICITAR_WO": {
      // Atleta sinaliza que não vai conseguir jogar a rodada (Cap. 07 —
      // "Impossibilidade justificada"). Fica pendente até o admin decidir;
      // NÃO altera a partida ainda — só a decisão aprovada faz isso.
      const {
        id, matchId, athleteId, athleteName, adversarioId, adversarioNome,
        round, justificativa, comprovanteUrl, criadoEm,
      } = action.payload;
      const nova = {
        id, matchId, athleteId, athleteName, adversarioId, adversarioNome,
        round, justificativa, comprovanteUrl: comprovanteUrl || null,
        status: "pendente", criadoEm, respondidoEm: null, motivoRecusa: null,
      };
      return { ...state, solicitacoesWo: [nova, ...state.solicitacoesWo] };
    }

    case "CANCELAR_SOLICITACAO_WO": {
      // Atleta retira o próprio pedido antes do admin decidir (mudou de ideia,
      // conseguiu resolver, etc.). Só remove se ainda estiver pendente.
      const { id } = action.payload;
      return { ...state, solicitacoesWo: state.solicitacoesWo.filter(s => s.id !== id) };
    }

    case "APLICAR_WO": {
      // Classifica um W.O. numa partida. Justificado anula; Culposo/A Favor
      // gravam a classificação (pontos entram no processamento da rodada).
      const { matchId, tipo, faltosoId, beneficiarioId } = action.payload;
      const matches = state.matches.map(m => {
        if (m.id !== matchId) return m;
        if (tipo === "justificado") return { ...m, rejeitado: true, motivoRejeicao: "W.O. Justificado" };
        return { ...m, woTipo: tipo, woFaltosoId: tipo === "culposo" ? (faltosoId || null) : null, woBeneficiarioId: beneficiarioId || null };
      });
      let athletes = state.athletes;
      if (tipo === "culposo" && faltosoId) {
        athletes = state.athletes.map(a => a.id === faltosoId ? { ...a, woCulpososTemporada: (a.woCulpososTemporada || 0) + 1 } : a);
      }
      return { ...state, matches, athletes };
    }

    case "MARCAR_WO_NOTIFICADO": {
      // Marca (e persiste) que o admin já disparou a notificação de W.O. pra um
      // dos atletas. Antes era só visual/local e sumia no refresh.
      const { id, quem } = action.payload;
      const campo = quem === "solicitante" ? "notificadoSolicitante" : "notificadoAdversario";
      const solicitacoesWo = state.solicitacoesWo.map(s =>
        s.id === id ? { ...s, [campo]: true } : s
      );
      return { ...state, solicitacoesWo };
    }

    case "RESPONDER_WO": {
      // Admin aprova ou recusa. Aprovado = aciona o MESMO mecanismo que já
      // existe pra "partida rejeitada/anulada" (usado hoje em divergências de
      // placar): a partida some do cálculo de rating, ninguém pontua nem
      // perde — exatamente a consequência do W.O. Justificado (Cap. 07).
      const { id, matchId, aprovado, motivoRecusa, justificativa } = action.payload;
      const now = new Date().toISOString();
      const solicitacoesWo = state.solicitacoesWo.map(s =>
        s.id === id
          ? { ...s, status: aprovado ? "aprovado" : "recusado", respondidoEm: now, motivoRecusa: motivoRecusa || null }
          : s
      );
      let matches = state.matches;
      if (aprovado) {
        matches = state.matches.map(m =>
          m.id === matchId
            ? { ...m, rejeitado: true, motivoRejeicao: `W.O. Justificado — ${justificativa || ""}`.trim() }
            : m
        );
      }
      return { ...state, solicitacoesWo, matches };
    }

    case "PROCESSAR_RODADA": {
      // Aplica o cálculo de rating (Tabela CBTM) para todas as partidas já
      // validadas de uma rodada específica, ainda não calculadas. Processa em
      // ordem de validação para manter a matemática do rating consistente
      // (cada partida usa o rating já atualizado pelas anteriores do lote).
      const { round } = action.payload;

      // Trava de sequência: a numeração de rodada cresce o par todo mês
      // (mês 1 = rodadas 1/2, mês 2 = rodadas 3/4, ...). A rodada PAR
      // (2ª do par mensal) só pode ser calculada depois que a rodada
      // ÍMPAR anterior (1ª do par) já estiver 100% calculada — senão o
      // rating usado no cálculo ficaria desatualizado (Cap. 05/08).
      const rodadaAnteriorPendente = round % 2 === 0 && state.matches.some(
        m => m.round === round - 1 && m.validated && !m.calculado && !m.rejeitado
      );
      if (rodadaAnteriorPendente) return state;

      const pendentes = state.matches
        .filter(m => m.round === round && m.validated && !m.calculado && !m.rejeitado)
        .sort((a, b) => new Date(a.adminAprovadoEm || 0) - new Date(b.adminAprovadoEm || 0));

      let athletes = state.athletes;
      const idsProcessados = [];
      const infoPorPartida = {}; // matchId -> { favoritoId, diferencaRatingMomento } (base pra estatísticas)

      pendentes.forEach(match => {
        const p1 = athletes.find(a => a.id === match.p1Id);
        const p2 = athletes.find(a => a.id === match.p2Id);
        if (!p1 || !p2) return;
        const p1wins = match.score1 > match.score2;
        const favoritoId = p1.rating >= p2.rating ? p1.id : p2.id;
        const diferencaRatingMomento = Math.abs(p1.rating - p2.rating);
        const newR1 = calcElo(p1.rating, p2.rating, p1wins ? 1 : 0);
        const newR2 = calcElo(p2.rating, p1.rating, p1wins ? 0 : 1);
        const delta1 = newR1 - p1.rating;
        const delta2 = newR2 - p2.rating;
        const dataCalculo = match.adminAprovadoEm || new Date().toISOString();
        athletes = athletes.map(a => {
          if (a.id === match.p1Id) return {
            ...a, rating: newR1, saldoTemp: (a.saldoTemp||0) + delta1,
            wins: (a.wins||0) + (p1wins?1:0), losses: (a.losses||0) + (p1wins?0:1),
            ratingPico: Math.max(a.ratingPico || a.rating, newR1),
            ratingHistorico: [...(a.ratingHistorico||[]), { data: dataCalculo, rating: newR1 }].slice(-30),
          };
          if (a.id === match.p2Id) return {
            ...a, rating: newR2, saldoTemp: (a.saldoTemp||0) + delta2,
            wins: (a.wins||0) + (p1wins?0:1), losses: (a.losses||0) + (p1wins?1:0),
            ratingPico: Math.max(a.ratingPico || a.rating, newR2),
            ratingHistorico: [...(a.ratingHistorico||[]), { data: dataCalculo, rating: newR2 }].slice(-30),
          };
          return a;
        });
        idsProcessados.push(match.id);
        infoPorPartida[match.id] = { favoritoId, diferencaRatingMomento };
      });

      const matches = state.matches.map(m =>
        idsProcessados.includes(m.id)
          ? { ...m, calculado: true, favoritoId: infoPorPartida[m.id].favoritoId, diferencaRatingMomento: infoPorPartida[m.id].diferencaRatingMomento }
          : m
      );

      // Depois de aplicar a rodada, tira uma foto da posição de cada atleta
      // no ranking — alimenta o gráfico de "Evolução da posição" das Estatísticas.
      const dataSnapshot = new Date().toISOString();
      const rankingAtual = [...athletes]
        .filter(a => estaNoRanking(a, matches))
        .sort(cmpRanking(matches));
      const posicaoPorId = {};
      rankingAtual.forEach((a,i) => { posicaoPorId[a.id] = i+1; });
      athletes = athletes.map(a => posicaoPorId[a.id] ? {
        ...a, posicaoHistorico: [...(a.posicaoHistorico||[]), { data: dataSnapshot, posicao: posicaoPorId[a.id] }].slice(-30),
      } : a);

      return { ...state, athletes, matches };
    }

    case "AVANCAR_RODADA": {
      // Trava de segurança (Cap. 13): respeita o nº de rodadas configurado.
      if (Math.max(0, ...state.matches.map(m => m.round || 0)) >= (state.rodadasPorTemporada || 6)) return state;
      // No modelo por rating, cada "avanço" gera o próximo PAR MENSAL (2 rodadas),
      // pareando pelo rating vigente e evitando repetir confrontos da temporada (Cap. 03).
      const ativos = state.athletes.filter(a => a.status === "ativo" && !a.pendenteCircuito);
      const key = state.keys[0];
      const roundBase = Math.max(0, ...state.matches.map(m => m.round || 0));

      const { rodada1, rodada2, bye1, bye2 } = gerarPareamentoPorRating(ativos, state.matches);

      // Próximo mês no calendário fixo
      const hoje = new Date();
      const ano = hoje.getFullYear(), mes = hoje.getMonth();
      const prazoR1 = new Date(ano, mes, 15).toISOString().split("T")[0];
      const prazoR2 = new Date(ano, mes, 25).toISOString().split("T")[0];

      const mkMatch = (pair, round, prazo) => ({
        id: `m_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
        keyId: key?.id || "key_1", round,
        p1Id: pair.p1, p2Id: pair.p2,
        score1: null, score2: null,
        p1Submitted: null, p2Submitted: null,
        validated: false,
        deadline: prazo, scoreDeadline: prazo,
      });

      const rA = roundBase + 1, rB = roundBase + 2;
      const newMatches = [
        ...rodada1.map(p => mkMatch(p, rA, prazoR1)),
        ...rodada2.map(p => mkMatch(p, rB, prazoR2)),
      ];

      const keys = state.keys.map(k => ({
        ...k, currentRound: rB,
        byes: { ...(k.byes||{}), [rA]: bye1, [rB]: bye2 },
      }));

      return { ...state, keys, matches: [...state.matches, ...newMatches] };
    }

    case "DEFINIR_RODADAS": {
      // Define quantas rodadas a temporada tem (par, mínimo 2 — o mês publica 2 por vez).
      const n = action.payload?.rodadas;
      if (typeof n !== "number" || n < 2 || n % 2 !== 0) return state;
      return { ...state, rodadasPorTemporada: n };
    }

    case "LOAD_FROM_DB": {
      const { athletes, matches, keys, phase, temporadaNumero, temporadaAno, rodadasPorTemporada, mensagensEnviadas, solicitacoesWo } = action.payload;
      return {
        ...state, athletes, matches, keys, phase,
        rodadasPorTemporada: rodadasPorTemporada ?? state.rodadasPorTemporada,
        temporadaNumero: temporadaNumero ?? state.temporadaNumero,
        temporadaAno: temporadaAno ?? state.temporadaAno,
        mensagensEnviadas: mensagensEnviadas ?? state.mensagensEnviadas,
        solicitacoesWo: solicitacoesWo ?? state.solicitacoesWo,
      };
    }

    case "EDITAR_ATLETA": {
      const { id, nome, telefone, apelido, rating, status } = action.payload;
      const athletes = state.athletes.map(a =>
        a.id === id ? { ...a, name: nome, phone: telefone, apelido: apelido||null, rating, status } : a
      );
      return { ...state, athletes };
    }

    case "EXCLUIR_ATLETA": {
      const athletes = state.athletes.filter(a => a.id !== action.payload.id);
      return { ...state, athletes };
    }

    default: return state;
  }
}

// ── UTILS ────────────────────────────────────────────────────────────────────
const fmtDate = d => d ? d.split("-").reverse().join("/") : "-";
const medalColor = i => i===0?"#FFD700":i===1?"#C0C0C0":i===2?"#CD7F32":"#6B7280";

// Confronto direto entre dois atletas na temporada (só partidas validadas e não
// anuladas): >0 se `aId` venceu mais, <0 se `bId` venceu mais.
function confrontoDireto(aId, bId, matches) {
  let av = 0, bv = 0;
  (matches || []).forEach(m => {
    if (m.rejeitado || !m.validated) return;
    if (m.score1 == null || m.score2 == null) return;
    if (!((m.p1Id === aId && m.p2Id === bId) || (m.p1Id === bId && m.p2Id === aId))) return;
    const vencedor = m.score1 > m.score2 ? m.p1Id : m.p2Id;
    if (vencedor === aId) av++; else if (vencedor === bId) bv++;
  });
  return av - bv;
}

// Comparador oficial do ranking da temporada (Regulamento Cap. 09):
// 1) saldo de pontos · 2) vitórias · 3) confronto direto · 4) rating.
function cmpRanking(matches) {
  return (a, b) => {
    if ((b.saldoTemp||0) !== (a.saldoTemp||0)) return (b.saldoTemp||0) - (a.saldoTemp||0);
    if ((b.wins||0) !== (a.wins||0)) return (b.wins||0) - (a.wins||0);
    const h2h = confrontoDireto(a.id, b.id, matches);
    if (h2h !== 0) return -h2h; // quem venceu o confronto direto vem primeiro
    return (b.rating||0) - (a.rating||0);
  };
}
function getH2H(matches, idA, idB) {
  const jogos = matches
    .filter(m => m.validated && ((m.p1Id === idA && m.p2Id === idB) || (m.p1Id === idB && m.p2Id === idA)))
    .map(m => {
      const aEhP1 = m.p1Id === idA;
      const scoreA = aEhP1 ? m.score1 : m.score2;
      const scoreB = aEhP1 ? m.score2 : m.score1;
      return { matchId: m.id, round: m.round, scoreA, scoreB, venceuA: scoreA > scoreB };
    });
  const winsA = jogos.filter(j => j.venceuA).length;
  const winsB = jogos.length - winsA;
  return { jogos, winsA, winsB, total: jogos.length };
}

function deadlineStatus(dateStr) {
  if (!dateStr) return { color:"#7d9188", label:"", urgent:false };
  const today = new Date(); today.setHours(0,0,0,0);
  const deadline = new Date(dateStr);
  const days = Math.ceil((deadline - today) / (1000*60*60*24));
  if (days < 0) return { color:"#c25a45", label:`⚠️ Vencido há ${Math.abs(days)}d`, urgent:true };
  if (days === 0) return { color:"#c25a45", label:"⚠️ Vence hoje!", urgent:true };
  if (days <= 2) return { color:"#fb923c", label:`🔥 ${days}d restante${days>1?"s":""}`, urgent:true };
  if (days <= 3) return { color:"#fb923c", label:`⏰ ${days}d restantes`, urgent:true };
  if (days <= 5) return { color:"#9C6F3E", label:`⏰ ${days}d restantes`, urgent:false };
  return { color:"#7d9188", label:`até ${fmtDate(dateStr)}`, urgent:false };
}

