function PinPromptModal({ onSubmit, onCancel }) {
  const [pin, setPin] = useState("");
  function confirmar() {
    if (!pin) return;
    onSubmit(pin);
  }
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(17,28,25,0.92)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{width:"100%",maxWidth:340,background:T.verdeCard,borderRadius:18,padding:24,border:`1px solid ${T.bordaSuave}`,textAlign:"center",boxSizing:"border-box"}}>
        <div style={{fontSize:28,marginBottom:8}}>🔐</div>
        <div style={{fontFamily:T.serif,fontSize:19,color:T.offwhite,marginBottom:6}}>Confirme seu PIN</div>
        <div style={{fontSize:12,color:T.cinza,marginBottom:18,lineHeight:1.5}}>
          Primeira ação de escrita desta sessão — confirme o PIN pra continuar. Não pede de novo até você fechar o navegador.
        </div>
        <input
          value={pin} onChange={e=>setPin(e.target.value.replace(/\D/g,""))}
          type="password" inputMode="numeric" placeholder="····" autoFocus
          onKeyDown={e=>e.key==="Enter" && confirmar()}
          style={{width:"100%",boxSizing:"border-box",background:T.verde,border:`1px solid ${T.borda}`,borderRadius:10,color:T.offwhite,padding:"14px",fontFamily:T.mono,fontSize:22,textAlign:"center",letterSpacing:8,outline:"none",marginBottom:16}}/>
        <Btn onClick={confirmar} color={T.terracota} full disabled={!pin}>Confirmar</Btn>
        <button onClick={onCancel} style={{width:"100%",marginTop:8,fontFamily:T.mono,fontSize:11,letterSpacing:1,textTransform:"uppercase",color:T.cinza,background:"transparent",border:"none",cursor:"pointer",padding:"8px 0"}}>Cancelar</button>
      </div>
    </div>
  );
}

export default function App() {
  const [state, dispatch] = useReducer(reducer, INIT);
  // ── Restaurar sessão do localStorage ─────────────────────────
  const sessaoSalva = (() => {
    try { return JSON.parse(localStorage.getItem("ctm_sessao") || "{}"); } catch { return {}; }
  })();

  const [isAdmin, setIsAdmin] = useState(sessaoSalva.isAdmin || false);
  const [currentAthlete, setCurrentAthlete] = useState(sessaoSalva.athleteId ? {id: sessaoSalva.athleteId} : null);
  const [isVisitante, setIsVisitante] = useState(sessaoSalva.isVisitante || false);
  const [mostrarBoasVindasVisitante, setMostrarBoasVindasVisitante] = useState(false);
  const [tab, setTab] = useState(sessaoSalva.tab || "dashboard");
  const [dbStatus, setDbStatus] = useState("loading");
  const [dbMsg, setDbMsg] = useState("");
  // Confirmação de PIN pra ações de escrita do admin (Edge Function admin-action).
  // null = nenhum prompt aberto; senão, { onSubmit, onCancel }.
  const [pinPrompt, setPinPrompt] = useState(null);
  // Mapa {id: telefone} carregado sob demanda (com PIN) só quando alguma
  // tela de admin realmente precisa mostrar telefone — não no login geral.
  const [telefones, setTelefones] = useState({});

  // ── Salvar sessão quando muda ──────────────────────────────
  useEffect(() => {
    const sessao = {
      isAdmin,
      athleteId: currentAthlete?.id || null,
      isVisitante,
      tab,
    };
    localStorage.setItem("ctm_sessao", JSON.stringify(sessao));
  }, [isAdmin, currentAthlete, isVisitante, tab]);

  // ── Carregar dados do Supabase ao iniciar ──────────────────
  useEffect(() => { loadFromSupabase(); }, []);

  async function loadFromSupabase() {
    setDbStatus("loading");
    try {
      const [atletas, partidas, chaves, config] = await Promise.all([
        db.getAtletas(), db.getPartidas(), db.getChaves(), db.getConfig(),
      ]);
      // Busca isolada: se a tabela mensagens_enviadas ainda não existir (migration
      // não rodada), isso NÃO pode travar o carregamento do resto do app.
      let mensagensLog = [];
      try { mensagensLog = await db.getMensagensEnviadas(); }
      catch(e) { console.warn("Histórico de mensagens indisponível (migration pendente?):", e.message); }
      // Mesma cautela pra solicitacoes_wo — tabela nova, migration pode ainda não ter rodado.
      let solicitacoesWoLog = [];
      try { solicitacoesWoLog = await db.getSolicitacoesWo(); }
      catch(e) { console.warn("Solicitações de W.O. indisponíveis (migration pendente?):", e.message); }
      const athletesMapped = (atletas||[]).map(mapAtletaFromDb);
      const matchesMapped = (partidas||[]).map(m => ({
        id: m.id, keyId: m.chave_id, round: m.rodada,
        p1Id: m.atleta1_id, p2Id: m.atleta2_id,
        score1: m.placar1, score2: m.placar2,
        p1Submitted: m.p1_placar1!=null ? {score1:m.p1_placar1,score2:m.p1_placar2} : null,
        p1SubAt: m.p1_enviado_em,
        p2Submitted: m.p2_placar1!=null ? {score1:m.p2_placar1,score2:m.p2_placar2} : null,
        p2SubAt: m.p2_enviado_em,
        validated: m.validado, validadoPorAdmin: m.validado_por_admin,
        adminAprovadoEm: m.admin_aprovado_em,
        calculado: m.calculado ?? true,
        imputadoPeloAdmin: m.imputado_pelo_admin || false,
        rejeitado: m.rejeitado, motivoRejeicao: m.motivo_rejeicao,
        deadline: m.prazo,
        criadoEm: m.criado_em || null,
        resultadoComunicado: m.resultado_comunicado || false,
        woTipo: m.wo_tipo || null,
        woFaltosoId: m.wo_faltoso_id || null,
        woBeneficiarioId: m.wo_beneficiario_id || null,
        favoritoId: m.favorito_id || null,
        diferencaRatingMomento: m.diferenca_rating_momento ?? null,
      }));
      const keysMapped = (chaves||[]).map(k => ({
        id: k.id, name: k.nome, currentRound: k.rodada_atual, rounds:[],
        athleteIds: athletesMapped.filter(a=>a.key===k.id).map(a=>a.id),
      }));
      const mensagensEnviadasMapped = (mensagensLog||[]).map(m => ({
        id: m.id, athleteId: m.atleta_id, athleteName: m.atleta_nome,
        categoria: m.categoria, categoriaLabel: m.categoria_label,
        texto: m.texto, enviadoEm: m.enviado_em, matchId: m.match_id || null,
      }));
      const solicitacoesWoMapped = (solicitacoesWoLog||[]).map(s => ({
        id: s.id, matchId: s.match_id, athleteId: s.atleta_id, athleteName: s.atleta_nome,
        adversarioId: s.adversario_id, adversarioNome: s.adversario_nome, round: s.round,
        justificativa: s.justificativa, comprovanteUrl: s.comprovante_url,
        status: s.status, criadoEm: s.criado_em, respondidoEm: s.respondido_em,
        motivoRecusa: s.motivo_recusa,
        notificadoSolicitante: s.notificado_solicitante || false,
        notificadoAdversario: s.notificado_adversario || false,
      }));
      dispatch({ type:"LOAD_FROM_DB", payload:{
        athletes: athletesMapped, matches: matchesMapped,
        keys: keysMapped, phase: config?.[0]?.fase||"inscricoes",
        temporadaNumero: config?.[0]?.temporada_numero || 1,
        temporadaAno: config?.[0]?.temporada_ano || new Date().getFullYear(),
        rodadasPorTemporada: config?.[0]?.rodadas_por_temporada || 6,
        mensagensEnviadas: mensagensEnviadasMapped,
        solicitacoesWo: solicitacoesWoMapped,
      }});
      // Restaurar atleta completo da sessão após carregar do banco
      if (sessaoSalva.athleteId) {
        const atletaCompleto = athletesMapped.find(a => a.id === sessaoSalva.athleteId);
        if (atletaCompleto) setCurrentAthlete(atletaCompleto);
        else { setCurrentAthlete(null); localStorage.removeItem("ctm_sessao"); }
      }
      setDbStatus("ok");
    } catch(e) {
      console.error(e);
      setDbStatus("error");
      setDbMsg(e.message);
    }
  }

  // Resolve com o PIN em cache, ou abre o PinPromptModal e espera a confirmação.
  // Rejeita se o admin cancelar o prompt.
  function obterPin() {
    const cached = getPinCache();
    if (cached) return Promise.resolve(cached);
    return new Promise((resolve, reject) => {
      setPinPrompt({
        onSubmit: (pin) => { setPinCache(pin); setPinPrompt(null); resolve(pin); },
        onCancel: () => { setPinPrompt(null); reject(new Error("Confirmação de PIN cancelada.")); },
      });
    });
  }

  // Chama a Edge Function admin-action pra qualquer ação de escrita do admin.
  // Se o PIN vier errado (401) ou expirar, limpa o cache — a PRÓXIMA ação pede
  // confirmação de novo automaticamente, em vez de continuar tentando com um
  // PIN que já sabemos que está errado.
  async function chamarAdminAction(acao, payload) {
    const pin = await obterPin();
    const res = await fetch(`${SUPA_URL}/functions/v1/admin-action`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${SUPA_KEY}`,
        "apikey": SUPA_KEY,
      },
      body: JSON.stringify({ pin, acao, payload }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || !data.sucesso) {
      if (res.status === 401) clearPinCache();
      throw new Error(data.erro || `Erro ${res.status} ao executar ${acao}`);
    }
    return data.dados;
  }

  // Garante que o mapa {id: telefone} está carregado, buscando via Edge
  // Function (PIN) só na primeira vez que alguma tela realmente precisa —
  // chamadas seguintes reaproveitam o que já foi buscado nessa sessão.
  async function garantirTelefones() {
    if (Object.keys(telefones).length > 0) return telefones;
    try {
      const dados = await chamarAdminAction("LISTAR_TELEFONES", {});
      const mapa = {};
      (dados || []).forEach(t => { mapa[t.id] = t.telefone; });
      setTelefones(mapa);
      return mapa;
    } catch(e) {
      console.warn("Não consegui carregar telefones:", e.message);
      return {};
    }
  }

  async function dispatchAndSync(action) {
    dispatch(action);
    try { await syncToSupabase(action, state); }
    catch(e) {
      console.error(`[sync falhou] ${action.type}:`, e);
      setDbMsg(`Erro ao salvar (${action.type}): ${e.message}`);
    }
  }

  async function syncToSupabase(action, st) {
    if (action.type === "INSCRICAO_ADD") {
      const p = action.payload;
      // Checagem de duplicidade pela busca pública estreita (não precisa
      // mais da lista inteira de atletas com telefone no cliente).
      const telefoneFormatado = p.phone.replace(/\D/g, "");
      const existente = await buscarAtletaPorTelefonePublico(telefoneFormatado);
      if (existente) {
        setDbMsg("telefone_duplicado");
        return;
      }
      try {
        await db.insertAtleta({
          nome:p.name, telefone:telefoneFormatado, apelido:p.apelido||null, federado:p.federated,
          rating: p.federated?(p.rating||null):250,
          rating_inicial: p.federated?(p.rating||null):250,
          saldo_temp:0, status:"pendente",
          aceite_regulamento:p.aceiteRegulamento||false,
          data_aceite_regulamento:p.dataAceite||null,
          versao_regulamento:"v03-8",
          aceite_lgpd:p.aceiteLGPD||false,
          data_aceite_lgpd:p.dataAceite||null,
          inscrito_em:p.dataAceite||new Date().toISOString(),
        });
      } catch(e) {
        // Rede de segurança: trava de unicidade real no banco (atletas_telefone_unique).
        // Cobre o raro caso de duas inscrições simultâneas com o mesmo número.
        if (String(e.message||"").includes("atletas_telefone_unique") || String(e.message||"").includes("duplicate key")) {
          setDbMsg("telefone_duplicado");
          return;
        }
        throw e;
      }
      await loadFromSupabase();
    }
    else if (action.type === "INSCRICAO_VALIDAR") {
      const {id,rating,approved,motivo} = action.payload;
      await chamarAdminAction("INSCRICAO_VALIDAR", { id, rating, approved, motivo });
      await loadFromSupabase();
    }
    else if (action.type === "SUBMIT_RESULT") {
      const {matchId,athleteId,score1,score2} = action.payload;
      const match = st.matches.find(m=>m.id===matchId);
      const isP1 = match?.p1Id===athleteId;
      await db.updatePartida(matchId, isP1
        ? {p1_placar1:score1,p1_placar2:score2,p1_enviado_em:new Date().toISOString()}
        : {p2_placar1:score1,p2_placar2:score2,p2_enviado_em:new Date().toISOString()});
    }
    else if (action.type === "VALIDATE_RESULT") {
      const {matchId,approved,motivo} = action.payload;
      await chamarAdminAction("VALIDATE_RESULT", { matchId, approved, motivo });
      await loadFromSupabase();
    }
    else if (action.type === "DESFAZER_VALIDACAO") {
      const { matchId } = action.payload;
      await chamarAdminAction("DESFAZER_VALIDACAO", { matchId });
      await loadFromSupabase();
    }
    else if (action.type === "ADMIN_IMPUTAR_RESULTADO") {
      const { matchId, score1, score2 } = action.payload;
      await chamarAdminAction("ADMIN_IMPUTAR_RESULTADO", { matchId, score1, score2 });
      await loadFromSupabase();
    }
    else if (action.type === "ATUALIZAR_FOTO_ATLETA") {
      const { athleteId, url } = action.payload;
      await db.updateAtleta(athleteId, { foto_url: url });
    }
    else if (action.type === "ATUALIZAR_ESTILO_ATLETA") {
      const { athleteId, estilo } = action.payload;
      await db.updateAtleta(athleteId, { estilo_jogo: estilo });
    }
    else if (action.type === "REGISTRAR_MENSAGEM_ENVIADA") {
      // Registro no histórico é acessório: se falhar (tabela ausente, tipo de
      // coluna divergente, etc.), NÃO pode derrubar o "marcar como enviado".
      const { id, athleteId, athleteName, categoria, categoriaLabel, texto, enviadoEm, matchId } = action.payload;
      try {
        await chamarAdminAction("REGISTRAR_MENSAGEM_ENVIADA", {
          id, athleteId, athleteName, categoria, categoriaLabel, texto, enviadoEm, matchId,
        });
      } catch(e) {
        console.warn("Registro de mensagem no histórico falhou (seguindo mesmo assim):", e.message);
      }
    }
    else if (action.type === "DEFINIR_RODADAS") {
      await chamarAdminAction("DEFINIR_RODADAS", { rodadas: action.payload.rodadas });
    }
    else if (action.type === "APLICAR_WO") {
      await chamarAdminAction("APLICAR_WO", action.payload);
      await loadFromSupabase();
    }
    else if (action.type === "MARCAR_WO_NOTIFICADO") {
      const { id, quem } = action.payload;
      await chamarAdminAction("MARCAR_WO_NOTIFICADO", { id, quem });
    }
    else if (action.type === "SOLICITAR_WO") {
      const {
        id, matchId, athleteId, athleteName, adversarioId, adversarioNome,
        round, justificativa, comprovanteUrl, criadoEm,
      } = action.payload;
      await db.insertSolicitacaoWo({
        id, match_id: matchId,
        atleta_id: athleteId || null, atleta_nome: athleteName || null,
        adversario_id: adversarioId || null, adversario_nome: adversarioNome || null,
        round: round || null, justificativa,
        comprovante_url: comprovanteUrl || null,
        status: "pendente", criado_em: criadoEm,
      });
    }
    else if (action.type === "CANCELAR_SOLICITACAO_WO") {
      const { id } = action.payload;
      await db.deleteSolicitacaoWo(id);
    }
    else if (action.type === "RESPONDER_WO") {
      const { id, matchId, aprovado, motivoRecusa, justificativa } = action.payload;
      await chamarAdminAction("RESPONDER_WO", { id, matchId, aprovado, motivoRecusa, justificativa });
      await loadFromSupabase();
    }
    else if (action.type === "PROCESSAR_RODADA") {
      // O cálculo (rating, saldo, favorito, snapshot de posição de todo mundo)
      // agora é feito inteiro dentro da Edge Function — o servidor é a fonte
      // da verdade. Recarregamos do banco depois pra refletir o resultado real.
      const { round } = action.payload;
      await chamarAdminAction("PROCESSAR_RODADA", { round });
      await loadFromSupabase();
    }
    else if (action.type === "INICIAR_ETAPA") {
      // Validação de mínimo de 8 atletas, criação da chave, pareamento por
      // rating e geração das partidas — tudo isso já roda dentro da Edge
      // Function agora, então só recarregamos do banco depois.
      await chamarAdminAction("INICIAR_ETAPA", {});
      await loadFromSupabase();
    }
    else if (action.type === "MARCAR_RESULTADO_COMUNICADO") {
      const { matchId, comunicado } = action.payload;
      await chamarAdminAction("MARCAR_RESULTADO_COMUNICADO", { matchId, comunicado });
    }
    else if (action.type === "NOVA_TEMPORADA") {
      // Zera saldo/vitórias/derrotas, arquiva a posição final no histórico,
      // apaga partidas/chaves e avança o contador — tudo dentro da Edge
      // Function agora (ação de altíssimo impacto, ótima candidata a proteção).
      await chamarAdminAction("NOVA_TEMPORADA", {});
      await loadFromSupabase();
    }
    else if (action.type === "AVANCAR_RODADA") {
      // Pareamento do próximo par mensal também roda inteiro na Edge Function.
      await chamarAdminAction("AVANCAR_RODADA", {});
      await loadFromSupabase();
    }
    else if (action.type === "EDITAR_ATLETA") {
      const { id, nome, telefone, apelido, rating, status } = action.payload;
      await chamarAdminAction("EDITAR_ATLETA", { id, nome, telefone, apelido, rating, status });
      await loadFromSupabase();
    }
    else if (action.type === "INCLUIR_NO_CIRCUITO") {
      const { id } = action.payload;
      await chamarAdminAction("INCLUIR_NO_CIRCUITO", { id });
      await loadFromSupabase();
    }
    else if (action.type === "RECUSAR_CIRCUITO") {
      const { id } = action.payload;
      await chamarAdminAction("RECUSAR_CIRCUITO", { id });
      await loadFromSupabase();
    }
    else if (action.type === "ARQUIVAR_ATLETA") {
      const { id } = action.payload;
      await chamarAdminAction("ARQUIVAR_ATLETA", { id });
      await loadFromSupabase();
    }
    else if (action.type === "EXCLUIR_ATLETA") {
      const { id } = action.payload;
      await chamarAdminAction("EXCLUIR_ATLETA", { id });
      await loadFromSupabase();
    }
  }

  // Barra de status de conexão
  const DbBar = () => dbStatus==="error" ? (
    <div style={{background:"rgba(248,113,113,0.15)",borderLeft:"3px solid #c25a45",padding:"8px 14px",fontSize:11,color:"#c25a45"}}>
      ⚠️ Erro de conexão com banco de dados — {dbMsg}
    </div>
  ) : dbStatus==="loading" ? (
    <div style={{background:"rgba(77,163,255,0.1)",borderLeft:"3px solid #D85A30",padding:"8px 14px",fontSize:11,color:"#D85A30"}}>
      🔄 Sincronizando com o banco de dados...
    </div>
  ) : null;

  if (!isAdmin && !currentAthlete && !isVisitante) return (
    <LoginScreen
      onLogin={() => { setIsAdmin(true); setTab("dashboard"); }}
      onAthleteLogin={a => { setCurrentAthlete(a); setTab("meus_jogos"); }}
      onVisitante={() => { setIsVisitante(true); setTab("ranking"); setMostrarBoasVindasVisitante(true); }}
      athletes={state.athletes}
      onInscricao={p => dispatchAndSync({type:"INSCRICAO_ADD", payload:p})}
    />
  );

  return (
    <div style={{fontFamily:"Inter,sans-serif", background:"#1C2B27", minHeight:"100vh", maxWidth:480, margin:"0 auto", color:"#F0EAE0", paddingBottom:80}}>
      <Header isAdmin={isAdmin} isVisitante={isVisitante} athlete={currentAthlete} onLogout={() => { setIsAdmin(false); setCurrentAthlete(null); setIsVisitante(false); setTab("dashboard"); localStorage.removeItem("ctm_sessao"); clearPinCache(); }} />
      {pinPrompt && <PinPromptModal onSubmit={pinPrompt.onSubmit} onCancel={pinPrompt.onCancel}/>}
      {mostrarBoasVindasVisitante && <BoasVindasVisitanteModal onClose={()=>setMostrarBoasVindasVisitante(false)}/>}
      <DbBar/>

      <div style={{padding:"12px 16px 0"}}>
        {isAdmin ? (
          <AdminView state={state} dispatch={dispatchAndSync} tab={tab} setTab={setTab} telefones={telefones} garantirTelefones={garantirTelefones} />
        ) : isVisitante ? (
          <VisitanteView state={state} tab={tab} setTab={setTab} />
        ) : (
          <AthleteView state={state} dispatch={dispatchAndSync} athlete={currentAthlete} tab={tab} setTab={setTab} />
        )}
      </div>

      <BottomNav isAdmin={isAdmin} isVisitante={isVisitante} tab={tab} setTab={setTab} />
    </div>
  );
}

