function AthleteGames({ state, dispatch, athlete }) {
  const [perfilAberto, setPerfilAberto] = useState(false);
  const [estatisticasAbertas, setEstatisticasAbertas] = useState(false);
  const [cartaAberta, setCartaAberta] = useState(false);
  const [editarAberto, setEditarAberto] = useState(false);
  const myMatches = state.matches.filter(m => m.p1Id === athlete.id || m.p2Id === athlete.id);
  const open = myMatches.filter(m => !m.validated && !m.rejeitado);
  const done = myMatches.filter(m => m.validated);

  // Dados do atleta para o cabeçalho editorial
  const eu = state.athletes.find(a => a.id === athlete.id) || {};
  const ranking = [...state.athletes].filter(a=>estaNoRanking(a, state.matches)).sort(cmpRanking(state.matches));
  const minhaPos = ranking.findIndex(a => a.id === athlete.id);
  const saldo = eu.saldoTemp || 0;
  const saldoColor = saldo > 0 ? T.verde2 : saldo < 0 ? T.vermelho : T.cinza;
  const classificado = minhaPos >= 0 && minhaPos < 8;

  // Contagem crescente (0 → valor) no cabeçalho, conforme o handoff de design
  const posAnimado = useCountUp(minhaPos >= 0 ? minhaPos + 1 : 0);
  const saldoAnimado = useCountUp(Math.abs(saldo));
  const ratingAnimado = useCountUp(eu.rating || 250);
  const posStr = minhaPos >= 0 ? `${posAnimado}º` : "—";
  const saldoStr = saldo > 0 ? `+${saldoAnimado}` : saldo < 0 ? `-${saldoAnimado}` : `${saldoAnimado}`;

  return (
    <div>
      {perfilAberto && (
        <PerfilAtletaView
          state={state} athlete={eu}
          onClose={()=>setPerfilAberto(false)}
          onVerEstatisticas={()=>setEstatisticasAbertas(true)}
          onVerCarta={()=>setCartaAberta(true)}
        />
      )}
      {estatisticasAbertas && <EstatisticasView state={state} athlete={eu} onClose={()=>setEstatisticasAbertas(false)}/>}
      {cartaAberta && <CartaModal athlete={eu} posicao={minhaPos>=0?minhaPos+1:null} onClose={()=>setCartaAberta(false)} podeBaixar/>}
      {editarAberto && <EditarPerfilView athlete={eu} dispatch={dispatch} onClose={()=>setEditarAberto(false)}/>}
      <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8,marginBottom:20}}>
        <div style={{position:"relative"}}>
          <div onClick={()=>setPerfilAberto(true)} style={{cursor:"pointer"}}>
            <Avatar athlete={eu} size={76} fontSize={30} ring="rgba(216,90,48,0.5)"/>
          </div>
          <button onClick={()=>setEditarAberto(true)} style={{position:"absolute",bottom:-2,right:-2,width:26,height:26,borderRadius:"50%",border:`1px solid rgba(216,90,48,0.6)`,background:T.telaFundo,color:T.offwhite,fontSize:11,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>
            ✏️
          </button>
        </div>
        <button onClick={()=>setPerfilAberto(true)} style={{fontFamily:T.mono,fontSize:9,letterSpacing:1.4,textTransform:"uppercase",color:T.terracota,background:"transparent",border:"none",cursor:"pointer",padding:"2px 4px"}}>
          Ver perfil
        </button>
      </div>

      {/* Cabeçalho editorial: Posição/Pontos + Rating */}
      <div style={{display:"flex",gap:10,marginBottom:20}}>
        <div style={{flex:1.4,background:T.verdeCard,borderRadius:10,padding:"14px 16px",borderLeft:`3px solid ${T.terracota}`}}>
          <div style={{display:"flex",gap:14,alignItems:"flex-start"}}>
            <div style={{textAlign:"center"}}>
              <div style={{fontFamily:T.mono,fontSize:8,color:"#e0785a",letterSpacing:1.5,marginBottom:6}}>POSIÇÃO</div>
              <div style={{fontFamily:T.serif,fontSize:30,color:T.offwhite,lineHeight:1}}>{posStr}</div>
            </div>
            <div style={{textAlign:"center"}}>
              <div style={{fontFamily:T.mono,fontSize:8,color:"#e0785a",letterSpacing:1.5,marginBottom:6}}>PONTOS</div>
              <div style={{fontFamily:T.mono,fontSize:26,fontWeight:700,color:saldoColor,lineHeight:1.1}}>{saldoStr}</div>
            </div>
          </div>
          {classificado && <div style={{fontFamily:T.mono,fontSize:8,color:T.cinza,marginTop:10,letterSpacing:0.5}}>✓ ZONA DE CLASSIFICAÇÃO</div>}
        </div>
        <div style={{flex:1,background:T.verdeCard,borderRadius:10,padding:"14px 16px"}}>
          <div style={{textAlign:"center"}}>
            <div style={{fontFamily:T.mono,fontSize:8,color:T.cinza,letterSpacing:1.5,marginBottom:6}}>RATING</div>
            <div style={{fontFamily:T.serif,fontSize:30,color:T.offwhite,lineHeight:1}}>{ratingAnimado}</div>
          </div>
        </div>
      </div>

      <div style={{fontFamily:T.serif,fontSize:26,color:T.offwhite,lineHeight:1,marginBottom:4}}>Meus jogos</div>
      {open.length > 0 && (
        <div style={{fontFamily:T.mono,fontSize:10,color:T.cinza,letterSpacing:2,marginBottom:16}}>
          {open.length} {open.length===1?"PARTIDA":"PARTIDAS"} EM ABERTO
        </div>
      )}

      {open.length === 0 && <Card><div style={{fontSize:13,color:T.cinza,textAlign:"center",padding:16}}>Nenhuma partida em aberto.</div></Card>}
      {open.map(m => <SubmitMatchCard key={m.id} m={m} state={state} dispatch={dispatch} athlete={athlete} />)}

      {done.length > 0 && <>
        <div style={{fontFamily:T.serif,fontSize:18,color:T.offwhite,marginTop:22,marginBottom:12}}>Já disputados</div>
        {done.map(m => {
          const souP1 = m.p1Id === athlete.id;
          const adversario = state.athletes.find(a => a.id === (souP1 ? m.p2Id : m.p1Id));
          const meuScore = souP1 ? m.score1 : m.score2;
          const scoreAdv = souP1 ? m.score2 : m.score1;
          const venci = meuScore > scoreAdv;
          return (
            <div key={m.id} style={{display:"flex",alignItems:"center",gap:12,padding:"13px 0",borderTop:`1px solid ${T.bordaSuave}`}}>
              <span style={{fontFamily:T.mono,fontSize:9,color:T.cinza,width:20,flexShrink:0}}>R{m.round}</span>
              <Avatar athlete={adversario} size={32} fontSize={13}/>
              <span style={{flex:1,fontSize:14,color:T.offwhite,minWidth:0,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{nomeExibicao(adversario)}</span>
              <span style={{fontFamily:T.mono,fontSize:13,color:"rgba(240,234,224,0.85)"}}>{meuScore}–{scoreAdv}</span>
              <span style={{width:24,height:24,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:T.mono,fontWeight:700,fontSize:12,flexShrink:0,
                background: venci ? T.terracota : "rgba(240,234,224,0.12)", color: venci ? T.offwhite : "rgba(240,234,224,0.7)"}}>
                {venci ? "V" : "D"}
              </span>
            </div>
          );
        })}
      </>}
    </div>
  );
}

// ── SOLICITAR W.O. JUSTIFICADO (atleta sinaliza que não vai jogar) ───────────
// Cap. 07 do regulamento: "Impossibilidade justificada". O atleta descreve o
// motivo (+ comprovante opcional); vira um pedido pendente até o admin decidir.
function SolicitarWoModal({ m, athlete, adversario, dispatch, onClose }) {
  const [justificativa, setJustificativa] = useState("");
  const [comprovanteFile, setComprovanteFile] = useState(null);
  const [comprovantePreview, setComprovantePreview] = useState(null);
  const [enviando, setEnviando] = useState(false);
  const [erro, setErro] = useState("");
  const inputCameraRef = useRef(null);
  const inputGaleriaRef = useRef(null);

  const ds = deadlineStatus(m.scoreDeadline || m.deadline);

  function handleFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setComprovanteFile(file);
    setComprovantePreview(URL.createObjectURL(file));
  }

  async function enviar() {
    const texto = justificativa.trim();
    if (texto.length < 10) {
      setErro("Escreva um pouco mais sobre o motivo (mínimo 10 caracteres).");
      return;
    }
    setEnviando(true);
    setErro("");
    try {
      let comprovanteUrl = null;
      if (comprovanteFile) {
        const blob = await resizeImageFile(comprovanteFile);
        comprovanteUrl = await uploadComprovanteWo(m.id, blob);
      }
      dispatch({
        type: "SOLICITAR_WO",
        payload: {
          id: `wo_${m.id}_${Date.now()}`,
          matchId: m.id,
          athleteId: athlete.id,
          athleteName: nomeExibicao(athlete),
          adversarioId: adversario?.id || null,
          adversarioNome: adversario ? nomeExibicao(adversario) : null,
          round: m.round,
          justificativa: texto,
          comprovanteUrl,
          criadoEm: new Date().toISOString(),
        },
      });
      onClose();
    } catch (e) {
      setErro("Não consegui enviar agora. Tente de novo em instantes.");
    } finally {
      setEnviando(false);
    }
  }

  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(17,28,25,0.88)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div onClick={e=>e.stopPropagation()} style={{width:"100%",maxWidth:380,background:T.verdeCard,borderRadius:18,padding:20,border:`1px solid ${T.bordaSuave}`,maxHeight:"88vh",overflowY:"auto",boxSizing:"border-box"}}>
        <div style={{fontFamily:T.serif,fontSize:20,color:T.offwhite,marginBottom:6}}>Não vou conseguir jogar</div>
        <div style={{fontSize:12,color:T.cinza,marginBottom:16,lineHeight:1.5}}>
          Isso vira um pedido de <b style={{color:T.offwhite}}>W.O. Justificado</b> — o admin vai analisar. Se aprovado, a rodada é anulada e ninguém perde pontos.
        </div>

        {ds.urgent && (
          <div style={{background:`${ds.color}1f`,border:`1px solid ${ds.color}55`,borderRadius:10,padding:"9px 12px",marginBottom:14,fontFamily:T.mono,fontSize:10.5,color:ds.color,lineHeight:1.5}}>
            ⚠️ O prazo da rodada está perto ({ds.label}). Pra garantir que o admin veja a tempo, avise também no grupo do WhatsApp.
          </div>
        )}

        <div style={{fontFamily:T.mono,fontSize:10,color:T.cinzaSuave,letterSpacing:1,textTransform:"uppercase",marginBottom:6}}>Motivo</div>
        <textarea value={justificativa} onChange={e=>setJustificativa(e.target.value)} rows={4} placeholder="Ex: viagem a trabalho já marcada, atestado médico, imprevisto..."
          style={{width:"100%",boxSizing:"border-box",background:T.verde,border:`1px solid ${T.borda}`,borderRadius:10,color:T.offwhite,padding:"10px 12px",fontSize:13,outline:"none",resize:"none",fontFamily:"inherit",marginBottom:12}}/>

        <div style={{fontFamily:T.mono,fontSize:10,color:T.cinzaSuave,letterSpacing:1,textTransform:"uppercase",marginBottom:6}}>Comprovante (opcional)</div>
        {comprovantePreview ? (
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
            <img src={comprovantePreview} alt="Comprovante" style={{width:52,height:52,objectFit:"cover",borderRadius:8,border:`1px solid ${T.bordaSuave}`}}/>
            <button onClick={()=>{setComprovanteFile(null);setComprovantePreview(null);}} style={{fontFamily:T.mono,fontSize:10,color:T.vermelho,background:"transparent",border:"none",cursor:"pointer",textDecoration:"underline"}}>remover</button>
          </div>
        ) : (
          <div style={{display:"flex",gap:8,marginBottom:12}}>
            <button onClick={()=>inputCameraRef.current?.click()} style={{fontFamily:T.mono,fontSize:9,letterSpacing:0.5,textTransform:"uppercase",color:T.offwhite,background:T.verde,border:`1px solid ${T.bordaSuave}`,borderRadius:14,padding:"8px 12px",cursor:"pointer"}}>📷 Tirar foto</button>
            <button onClick={()=>inputGaleriaRef.current?.click()} style={{fontFamily:T.mono,fontSize:9,letterSpacing:0.5,textTransform:"uppercase",color:T.offwhite,background:T.verde,border:`1px solid ${T.bordaSuave}`,borderRadius:14,padding:"8px 12px",cursor:"pointer"}}>🖼️ Galeria</button>
          </div>
        )}
        <input ref={inputCameraRef} type="file" accept="image/*" capture="environment" onChange={handleFile} style={{display:"none"}}/>
        <input ref={inputGaleriaRef} type="file" accept="image/*" onChange={handleFile} style={{display:"none"}}/>

        {erro && <div style={{fontSize:12,color:T.vermelho,marginBottom:10}}>{erro}</div>}

        <Btn onClick={enviar} color={T.terracota} full disabled={enviando}>{enviando ? "Enviando…" : "Enviar solicitação"}</Btn>
        <button onClick={onClose} style={{width:"100%",marginTop:8,fontFamily:T.mono,fontSize:11,letterSpacing:1,textTransform:"uppercase",color:T.cinza,background:"transparent",border:"none",cursor:"pointer",padding:"8px 0"}}>Cancelar</button>
      </div>
    </div>
  );
}

function SubmitMatchCard({ m, state, dispatch, athlete }) {
  const isP1 = m.p1Id === athlete.id;
  const mySubmit = isP1 ? m.p1Submitted : m.p2Submitted;
  const [s1, setS1] = useState(""), [s2, setS2] = useState("");
  const [sent, setSent] = useState(false);
  const [cartaAberta, setCartaAberta] = useState(false);
  const [woModalAberto, setWoModalAberto] = useState(false);
  // Minha solicitação de W.O. mais recente pra essa partida (se existir).
  const minhaSolicitacaoWo = state.solicitacoesWo
    .filter(sw => sw.matchId === m.id && sw.athleteId === athlete.id)
    .sort((a,b) => new Date(b.criadoEm) - new Date(a.criadoEm))[0];
  const woPendente = minhaSolicitacaoWo?.status === "pendente";
  const p1 = state.athletes.find(a=>a.id===m.p1Id);
  const p2 = state.athletes.find(a=>a.id===m.p2Id);
  const adversario = isP1 ? p2 : p1;
  const ranking = [...state.athletes].filter(a=>estaNoRanking(a, state.matches)).sort(cmpRanking(state.matches));
  const posicaoAdversario = (() => { const idx = ranking.findIndex(a => a.id === adversario?.id); return idx === -1 ? null : idx + 1; })();

  function submit() {
    if (!s1||!s2) return;
    dispatch({type:"SUBMIT_RESULT",payload:{matchId:m.id,athleteId:athlete.id,score1:parseInt(s1),score2:parseInt(s2)}});
    setSent(true);
  }

  return (
    <Card style={{border:`1px solid ${T.terracota}33`}}>
      {cartaAberta && <CartaModal athlete={adversario} posicao={posicaoAdversario} onClose={()=>setCartaAberta(false)}/>}
      {woModalAberto && (
        <SolicitarWoModal m={m} athlete={athlete} adversario={adversario} dispatch={dispatch} onClose={()=>setWoModalAberto(false)}/>
      )}
      {(() => {
        // Faixa de urgência: só aparece quando o prazo está apertado (urgent),
        // pra criar senso de urgência sem poluir quando ainda há tempo de sobra.
        const ds = deadlineStatus(m.scoreDeadline || m.deadline);
        if (!ds.urgent) return null;
        return (
          <div style={{
            display:"flex",alignItems:"center",justifyContent:"center",gap:8,
            background:`${ds.color}1f`,border:`1px solid ${ds.color}55`,borderRadius:10,
            padding:"9px 12px",marginBottom:12,
          }}>
            <span style={{fontFamily:T.mono,fontSize:11,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase",color:ds.color}}>
              {ds.label}
            </span>
            <span style={{fontFamily:T.mono,fontSize:9,letterSpacing:0.5,textTransform:"uppercase",color:"rgba(240,234,224,0.55)"}}>
              pra registrar o placar
            </span>
          </div>
        );
      })()}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
        <span style={{fontFamily:T.mono,fontSize:10,color:T.cinza,letterSpacing:1.5,textTransform:"uppercase"}}>Rodada {m.round}</span>
        {(() => {
          const ds = deadlineStatus(m.scoreDeadline || m.deadline);
          // Quando a faixa de urgência já está visível, aqui só mostramos a data
          // "seca" pra não repetir a mesma informação duas vezes.
          const texto = ds.urgent ? `Placar até ${fmtDate(m.scoreDeadline || m.deadline)}` : `Placar: ${ds.label}`;
          return <span style={{fontFamily:T.mono,fontSize:9,color:ds.urgent?T.cinza:ds.color,letterSpacing:0.8,fontWeight:400,textTransform:"uppercase"}}>{texto}</span>;
        })()}
      </div>
      <div style={{display:"flex",justifyContent:"center",alignItems:"center",gap:20,marginBottom:14}}>
        <div onClick={isP1?undefined:()=>setCartaAberta(true)} style={{cursor:isP1?"default":"pointer"}}>
          <Avatar athlete={p1} size={54} fontSize={20} ring={isP1?"rgba(216,90,48,0.55)":"rgba(240,234,224,0.16)"}/>
        </div>
        <div style={{textAlign:"center"}}>
          <div style={{width:18,height:18,borderRadius:"50%",background:T.terracota,margin:"0 auto",boxShadow:"inset -3px -3px 5px rgba(0,0,0,0.25)",animation:"ctm-ballBounce 1.3s ease-in-out infinite"}}/>
          <div style={{width:18,height:5,borderRadius:"50%",background:"rgba(0,0,0,0.4)",margin:"4px auto 0",animation:"ctm-ballShadow 1.3s ease-in-out infinite"}}/>
        </div>
        <div onClick={isP1?()=>setCartaAberta(true):undefined} style={{cursor:isP1?"pointer":"default"}}>
          <Avatar athlete={p2} size={54} fontSize={20} ring={!isP1?"rgba(216,90,48,0.55)":"rgba(240,234,224,0.16)"}/>
        </div>
      </div>
      <div style={{fontFamily:T.mono,fontSize:8.5,color:T.cinza,letterSpacing:0.5,textTransform:"uppercase",textAlign:"center",marginTop:-8,marginBottom:12}}>
        Toque na foto de {nomeExibicao(adversario).split(" ")[0]} pra ver a carta dele(a)
      </div>
      <div style={{fontFamily:T.serif,fontSize:18,color:T.offwhite,textAlign:"center",marginBottom:4,lineHeight:1.2}}>
        {nomeExibicao(p1)} <span style={{fontFamily:T.mono,fontSize:11,color:T.cinza,fontWeight:700}}> vs </span> {nomeExibicao(p2)}
      </div>
      <H2HBadge state={state} idA={m.p1Id} idB={m.p2Id} />
      <div style={{marginBottom:10}} />
      {woPendente ? (
        <div style={{background:`${T.madeira}1a`,border:`1px solid ${T.madeira}44`,borderRadius:9,padding:"12px 14px"}}>
          <div style={{fontFamily:T.mono,fontSize:11,fontWeight:700,color:T.madeira,textAlign:"center",letterSpacing:0.3,textTransform:"uppercase",marginBottom:8}}>
            📨 Solicitação de W.O. enviada
          </div>
          <div style={{fontSize:12,color:T.offwhite,lineHeight:1.5,marginBottom:10}}>"{minhaSolicitacaoWo.justificativa}"</div>
          <div style={{fontSize:11,color:T.cinza,marginBottom:10}}>Aguardando análise do admin. Se aprovado, a rodada é anulada e ninguém perde pontos.</div>
          <button onClick={()=>dispatch({type:"CANCELAR_SOLICITACAO_WO",payload:{id:minhaSolicitacaoWo.id}})}
            style={{fontFamily:T.mono,fontSize:10,letterSpacing:0.5,color:T.vermelho,background:"transparent",border:"none",cursor:"pointer",textDecoration:"underline",padding:0}}>
            Retirar solicitação
          </button>
        </div>
      ) : (
        <>
          {minhaSolicitacaoWo?.status === "recusado" && (
            <div style={{background:`${T.vermelho}1a`,border:`1px solid ${T.vermelho}44`,borderRadius:9,padding:"10px 12px",marginBottom:12,fontSize:12,color:T.offwhite,lineHeight:1.5}}>
              <div style={{fontFamily:T.mono,fontSize:10,fontWeight:700,color:T.vermelho,letterSpacing:0.3,textTransform:"uppercase",marginBottom:4}}>❌ Solicitação de W.O. recusada</div>
              {minhaSolicitacaoWo.motivoRecusa && <div>{minhaSolicitacaoWo.motivoRecusa}</div>}
              <div style={{color:T.cinza,marginTop:4}}>Você ainda precisa registrar o placar normalmente.</div>
            </div>
          )}
          {mySubmit || sent ? (
            <div style={{background:`${T.verde2}1a`,borderRadius:9,padding:"10px 12px",fontFamily:T.mono,fontSize:11,fontWeight:700,color:T.verde2,textAlign:"center",letterSpacing:0.3,textTransform:"uppercase"}}>
              ✓ Resultado enviado — aguardando validação do admin
            </div>
          ) : (
            <>
              <div style={{fontFamily:T.mono,fontSize:10,color:T.cinzaSuave,letterSpacing:1,marginBottom:4,textTransform:"uppercase"}}>Informe apenas o placar em sets</div>
              <div style={{fontSize:11,color:T.cinza,marginBottom:12}}>Ex: vitória por 3×1 → digite 3 e 1</div>
              <div style={{display:"flex",gap:8,marginBottom:8}}>
                <div style={{flex:1,textAlign:"center",fontFamily:T.mono,fontSize:10,color:T.offwhite,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase"}}>{nomeExibicao(p1).split(" ")[0]}</div>
                <div style={{width:40,flexShrink:0}}/>
                <div style={{flex:1,textAlign:"center",fontFamily:T.mono,fontSize:10,color:T.offwhite,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase"}}>{nomeExibicao(p2).split(" ")[0]}</div>
              </div>
              <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:12}}>
                <div style={{flex:1,minWidth:0}}>
                  <input value={s1} onChange={e=>setS1(e.target.value.replace(/\D/g,"").slice(0,1))} type="tel" inputMode="numeric" placeholder="0"
                    style={{width:"100%",boxSizing:"border-box",background:T.verde,border:`1px solid ${T.borda}`,borderRadius:9,color:T.terracota,padding:"14px",fontFamily:T.serif,fontSize:28,textAlign:"center",outline:"none"}}/>
                </div>
                <div style={{width:40,flexShrink:0,textAlign:"center"}}>
                  <div style={{color:T.cinza,fontSize:20,fontWeight:800,lineHeight:1}}>×</div>
                  <div style={{fontFamily:T.mono,fontSize:9,color:T.borda,marginTop:4,textTransform:"uppercase",letterSpacing:0.5}}>sets</div>
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <input value={s2} onChange={e=>setS2(e.target.value.replace(/\D/g,"").slice(0,1))} type="tel" inputMode="numeric" placeholder="0"
                    style={{width:"100%",boxSizing:"border-box",background:T.verde,border:`1px solid ${T.borda}`,borderRadius:9,color:T.terracota,padding:"14px",fontFamily:T.serif,fontSize:28,textAlign:"center",outline:"none"}}/>
                </div>
              </div>
              <Btn onClick={submit} color={T.terracota} full disabled={!s1||!s2}>Enviar resultado</Btn>
              <button onClick={()=>setWoModalAberto(true)}
                style={{display:"block",width:"100%",marginTop:10,fontFamily:T.mono,fontSize:10,letterSpacing:0.5,textTransform:"uppercase",color:T.cinza,background:"transparent",border:"none",cursor:"pointer",padding:"4px 0",textAlign:"center"}}>
                Não vou conseguir jogar esta rodada
              </button>
            </>
          )}
        </>
      )}
      {(m.p1Submitted||m.p2Submitted) && !mySubmit && !sent && !woPendente && (
        <div style={{fontFamily:T.mono,fontSize:10,color:T.madeira,marginTop:8,textAlign:"center",letterSpacing:0.3,textTransform:"uppercase"}}>⚡ Adversário já enviou — aguardando seu resultado</div>
      )}
    </Card>
  );
}

function TabelaView({ state, athlete }) {
  if (state.keys.length === 0) return <Card><div style={{fontSize:13,color:"#7d9188",textAlign:"center",padding:16}}>Etapa ainda não iniciada.</div></Card>;
  const myKey = state.keys.find(k => k.athleteIds.includes(athlete.id));
  const allMatches = myKey ? state.matches.filter(m => m.keyId === myKey.id) : [];

  const rounds = useMemo(() => {
    const porRodada = {};
    allMatches.forEach(m => { (porRodada[m.round] = porRodada[m.round] || []).push(m); });
    return Object.keys(porRodada).map(Number).sort((a,b) => b-a).map(r => ({ round: r, matches: porRodada[r] }));
  }, [allMatches]);

  if (allMatches.length === 0) return <Card><div style={{fontSize:13,color:"#7d9188",textAlign:"center",padding:16}}>Nenhuma partida ainda.</div></Card>;

  const rodadasNums = rounds.map(r => r.round);
  const rangeRodadas = rodadasNums.length
    ? (Math.min(...rodadasNums) === Math.max(...rodadasNums) ? `rodada ${rodadasNums[0]}` : `rodadas ${Math.min(...rodadasNums)} a ${Math.max(...rodadasNums)}`)
    : "";

  return (
    <div>
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontFamily:T.serif,fontSize:30,color:T.offwhite,lineHeight:1}}>Tabela</div>
        <div style={{fontFamily:T.mono,fontSize:10,letterSpacing:2,textTransform:"uppercase",color:T.cinza,marginTop:6}}>Confrontos · {rangeRodadas}</div>
      </div>

      {rounds.map(({round, matches}) => {
        const todasResolvidas = matches.every(m => m.validated || m.rejeitado);
        const status = todasResolvidas ? (() => {
          const datas = matches.map(m=>m.adminAprovadoEm).filter(Boolean).map(d=>new Date(d).getTime());
          const maisRecente = datas.length ? new Date(Math.max(...datas)) : null;
          return `Realizada${maisRecente ? " · " + maisRecente.toLocaleDateString("pt-BR") : ""}`;
        })() : (() => {
          const prazo = matches.find(m=>m.deadline)?.deadline;
          return `Atual${prazo ? " · até " + fmtDate(prazo) : ""}`;
        })();

        return (
          <div key={round}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",margin:"14px 2px 10px"}}>
              <span style={{fontFamily:T.serif,fontSize:20,color:T.offwhite}}>Rodada {round}</span>
              <span style={{fontFamily:T.mono,fontSize:8.5,letterSpacing:1,textTransform:"uppercase",color:T.cinza}}>{status}</span>
            </div>

            {matches.map(m => {
              const p1 = state.athletes.find(a=>a.id===m.p1Id);
              const p2 = state.athletes.find(a=>a.id===m.p2Id);
              if (!p1 || !p2) return null;
              const done = m.validated;
              const you = m.p1Id === athlete.id || m.p2Id === athlete.id;
              const aWin = done && m.score1 > m.score2;
              const linhaJogador = (p, ganhou, score) => (
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:8}}>
                  <span style={{display:"flex",alignItems:"center",gap:8,minWidth:0,flex:1}}>
                    <Avatar athlete={p} size={26} fontSize={11}/>
                    <span style={{fontSize:13,color: done ? (ganhou?T.offwhite:"rgba(240,234,224,0.5)") : T.offwhite,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{nomeExibicao(p)}</span>
                  </span>
                  {done && <span style={{fontFamily:T.serif,fontSize:18,lineHeight:1,color:ganhou?T.terracota:"rgba(240,234,224,0.5)",flexShrink:0}}>{score}</span>}
                </div>
              );
              return (
                <div key={m.id} style={{
                  display:"flex", alignItems:"center", gap:12, padding:"11px 13px", borderRadius:12, marginBottom:7,
                  border:`1px solid ${you ? "rgba(216,90,48,0.3)" : T.bordaSuave}`,
                  background: you ? "rgba(216,90,48,0.09)" : "rgba(240,234,224,0.03)",
                }}>
                  <div style={{flex:1,minWidth:0}}>
                    {linhaJogador(p1, aWin, m.score1)}
                    <div style={{height:1,background:"rgba(240,234,224,0.08)",margin:"7px 0"}}/>
                    {linhaJogador(p2, !aWin, m.score2)}
                  </div>
                  {!done && (
                    <span style={{
                      fontFamily:T.mono,fontSize:8,letterSpacing:1,textTransform:"uppercase",whiteSpace:"nowrap",flexShrink:0,
                      padding:"6px 9px",borderRadius:16,
                      color: m.rejeitado ? T.vermelho : T.offwhite,
                      background: m.rejeitado ? "transparent" : T.terracota,
                      border: m.rejeitado ? `1px solid ${T.vermelho}55` : "none",
                    }}>
                      {m.rejeitado ? "W.O." : "Em aberto"}
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        );
      })}
      <div style={{height:20}}/>
    </div>
  );
}

// ── COMUNIDADE (aba nova do redesign) ─────────────────────────────────────────
// Feed calculado automaticamente a partir dos dados existentes — partidas
// validadas e atletas recém-aprovados — sem precisar de tabela nova no Supabase.
function tempoRelativo(ts) {
  const dias = Math.floor((Date.now() - ts) / 86400000);
  if (dias <= 0) return "Hoje";
  if (dias === 1) return "Há 1 dia";
  return `Há ${dias} dias`;
}

function ComunidadeView({ state, currentAthleteId, somenteAtletas = false }) {
  const [cartaAberta, setCartaAberta] = useState(null); // { athlete, posicao } | null

  // Diferente do Ranking: aqui é a lista geral de membros do clube, não o
  // ranking competitivo — atletas no backlog (aprovados, aguardando a
  // próxima rodada) devem aparecer normalmente.
  const ativos = useMemo(() => [...state.athletes]
    .filter(a => a.status === "ativo")
    .sort(cmpRanking(state.matches)),
    [state.athletes]);

  // Posição real no ranking (exclui backlog) — usada só pra abrir a carta.
  // Quem ainda está no backlog não tem posição de verdade; cai depois do
  // último colocado (mesma regra já usada no "Ver carta" da tela Etapa).
  const ranking = useMemo(() => [...state.athletes]
    .filter(a => estaNoRanking(a, state.matches))
    .sort(cmpRanking(state.matches)),
    [state.athletes, state.matches]);
  const posicaoDe = (athleteId) => { const idx = ranking.findIndex(a => a.id === athleteId); return idx === -1 ? null : idx + 1; };

  const feed = useMemo(() => {
    const eventos = [];
    state.matches.filter(m => m.validated && !m.rejeitado && m.adminAprovadoEm).forEach(m => {
      const p1 = state.athletes.find(a=>a.id===m.p1Id);
      const p2 = state.athletes.find(a=>a.id===m.p2Id);
      if (!p1 || !p2) return;
      const p1venceu = m.score1 > m.score2;
      const vencedor = p1venceu ? p1 : p2;
      const perdedor = p1venceu ? p2 : p1;
      const golsV = p1venceu ? m.score1 : m.score2;
      const golsP = p1venceu ? m.score2 : m.score1;
      eventos.push({
        ts: new Date(m.adminAprovadoEm).getTime(),
        atleta: vencedor,
        texto: `venceu ${nomeExibicao(perdedor)} por ${golsV}–${golsP}.`,
        tag: `Rodada ${m.round}`,
        tipo: "match",
      });
    });
    state.athletes.filter(a => a.status === "ativo" && a.inscritoEm).forEach(a => {
      eventos.push({
        ts: new Date(a.inscritoEm).getTime(),
        atleta: a,
        texto: "entrou para o clube.",
        tag: "Novo atleta",
        tipo: "new",
      });
    });
    return eventos.sort((a,b) => b.ts - a.ts).slice(0, 12);
  }, [state.matches, state.athletes]);

  const tagCores = {
    match: { color:"rgba(240,234,224,0.75)", bg:"rgba(240,234,224,0.1)" },
    new: { color:T.offwhite, bg:T.madeira },
    rank: { color:T.offwhite, bg:T.terracota },
  };

  return (
    <div>
      {cartaAberta && <CartaModal athlete={cartaAberta.athlete} posicao={cartaAberta.posicao} onClose={()=>setCartaAberta(null)}/>}
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontFamily:T.serif,fontSize:30,color:T.offwhite,lineHeight:1}}>Comunidade</div>
        <div style={{fontFamily:T.mono,fontSize:10,letterSpacing:2,textTransform:"uppercase",color:T.cinza,marginTop:6}}>
          Clube do Tênis de Mesa · {ativos.length} atletas
        </div>
      </div>

      {!somenteAtletas && <>
        <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:8}}>
          <span style={{fontFamily:T.mono,fontSize:10,letterSpacing:2,textTransform:"uppercase",color:T.cinza,whiteSpace:"nowrap"}}>No clube</span>
          <div style={{flex:1,height:1,background:T.bordaSuave}}/>
        </div>

        {feed.length === 0 && (
          <div style={{fontSize:13,color:T.cinza,textAlign:"center",padding:"16px 0"}}>Ainda não há novidades por aqui.</div>
        )}

        {feed.map((f, i) => {
          const c = tagCores[f.tipo] || tagCores.match;
          return (
            <div key={i} style={{display:"flex",gap:12,padding:"10px 0"}}>
              <Avatar athlete={f.atleta} size={38}/>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",alignItems:"center",gap:8}}>
                  <span style={{fontFamily:T.mono,fontSize:8,letterSpacing:0.6,textTransform:"uppercase",color:c.color,background:c.bg,padding:"3px 7px",borderRadius:12}}>{f.tag}</span>
                  <span style={{fontFamily:T.mono,fontSize:9,letterSpacing:0.5,textTransform:"uppercase",color:T.cinza}}>{tempoRelativo(f.ts)}</span>
                </div>
                <div style={{fontSize:13.5,lineHeight:1.4,marginTop:6,color:"rgba(240,234,224,0.8)"}}>
                  <span style={{color:T.offwhite,fontWeight:600}}>{nomeExibicao(f.atleta)}</span> {f.texto}
                </div>
              </div>
            </div>
          );
        })}
      </>}

      <div style={{marginTop:somenteAtletas?4:24}}>
        <div style={{fontFamily:T.mono,fontSize:10,letterSpacing:2,textTransform:"uppercase",color:T.cinza,marginBottom:14}}>Atletas do clube</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:"16px 8px"}}>
          {ativos.map(a => {
            const isMe = a.id === currentAthleteId;
            return (
              <div key={a.id} onClick={()=>setCartaAberta({athlete:a, posicao:posicaoDe(a.id)})} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:7,cursor:"pointer"}}>
                <Avatar athlete={a} size={56} fontSize={20} ring={isMe?"rgba(216,90,48,0.6)":"rgba(240,234,224,0.16)"}/>
                <span style={{fontSize:11,color:"rgba(240,234,224,0.8)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:"100%"}}>
                  {nomeExibicao(a).split(" ")[0]}
                </span>
              </div>
            );
          })}
        </div>
      </div>
      <div style={{height:20}}/>
    </div>
  );
}
